9	function cellKey([x, y]: Cell): string {
10	  return `${x},${y}`;
11	}
12	
13	function survives(isAlive: boolean, liveNeighbors: number): boolean {
14	  return liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
15	}
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveSet = new Set<string>(cells.map(cellKey));
19	  const neighbors = new Map<string, { cell: Cell; count: number }>();
20	
21	  for (const [x, y] of cells) {
22	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
23	      const cell: Cell = [x + dx, y + dy];
24	      const k = cellKey(cell);
25	      const existing = neighbors.get(k);
26	      neighbors.set(k, { cell, count: (existing?.count ?? 0) + 1 });
27	    }
28	  }
29	
30	  const result: Cell[] = [];
31	  for (const [k, { cell, count }] of neighbors) {
32	    if (survives(liveSet.has(k), count)) {
33	      result.push(cell);
34	    }
35	  }
36	  return result;
37	}
